import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '@/locales/zh-CN'
import type { Locale } from '@/locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')
export const FALLBACK_LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Partial<Locale>>> = Symbol('brutx-ui-fallback-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export interface LocaleOptions {
    locale: MaybeRef<Locale>
    fallbackLocale?: MaybeRef<Partial<Locale>>
}

export function provideLocale(localeOrOptions: MaybeRef<Locale> | LocaleOptions): void {
    // 检查是否是 LocaleOptions 格式（包含 locale 属性）
    if (
        typeof localeOrOptions === 'object' &&
        localeOrOptions !== null &&
        'locale' in localeOrOptions
    ) {
        const options = localeOrOptions as LocaleOptions
        provide(LOCALE_INJECTION_KEY, options.locale)
        if (options.fallbackLocale) {
            provide(FALLBACK_LOCALE_INJECTION_KEY, options.fallbackLocale)
        }
    } else {
        // 直接传入 MaybeRef<Locale> 格式（向后兼容）
        provide(LOCALE_INJECTION_KEY, localeOrOptions as MaybeRef<Locale>)
    }
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (typeof result !== 'object' || result === null) return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)
    const injectedFallback = inject<MaybeRef<Partial<Locale>> | undefined>(FALLBACK_LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    const fallbackLocale = computed<Partial<Locale>>(() => {
        return injectedFallback ? unref(injectedFallback) : {}
    })

    function t(path: string, params?: Record<string, string | number>): string {
        // 1. 尝试从用户 locale 查找
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        // 2. 尝试从自定义 fallback locale 查找
        if (fallbackLocale.value && Object.keys(fallbackLocale.value).length > 0) {
            const fallbackVal = resolveByPath(fallbackLocale.value, path)
            if (fallbackVal !== undefined) return interpolate(fallbackVal, params)
        }

        // 3. 尝试从默认 zhCN 查找
        const zhCNVal = resolveByPath(zhCN, path)
        if (zhCNVal !== undefined) return interpolate(zhCNVal, params)

        // 4. 返回 path 原文
        return path
    }

    return { locale, t }
}

import { computed, toValue, type ComputedRef, type MaybeRefOrGetter } from 'vue'
import { cn } from '@/lib/utils'

export interface SelectableTriggerState {
    hasValue: boolean
}

export type SelectableTriggerClass =
    | MaybeRefOrGetter<string | false | null | undefined>
    | ((state: SelectableTriggerState) => string | false | null | undefined)

export interface UseSelectableTriggerOptions<TValue = unknown> {
    modelValue?: MaybeRefOrGetter<TValue | null | undefined>
    hasValue?: MaybeRefOrGetter<boolean | undefined>
    getHasValue?: (value: TValue | null | undefined) => boolean
    baseClass?: SelectableTriggerClass
    class?: MaybeRefOrGetter<string | false | null | undefined>
    emptyClass?: MaybeRefOrGetter<string | false | null | undefined>
}

export interface UseSelectableTriggerReturn {
    hasValue: ComputedRef<boolean>
    triggerClasses: ComputedRef<string>
}

export function useSelectableTrigger<TValue = unknown>(
    options: UseSelectableTriggerOptions<TValue> = {}
): UseSelectableTriggerReturn {
    const hasValue = computed(() => {
        const explicitHasValue = toValue(options.hasValue)
        if (explicitHasValue !== undefined) return explicitHasValue

        const value = toValue(options.modelValue)
        if (options.getHasValue) return options.getHasValue(value)
        if (Array.isArray(value)) return value.length > 0
        if (typeof value === 'string') return value.length > 0
        return value !== null && value !== undefined
    })

    const triggerClasses = computed(() => {
        const state = { hasValue: hasValue.value }
        const baseClass = typeof options.baseClass === 'function'
            ? options.baseClass(state)
            : toValue(options.baseClass)
        const emptyClass = options.emptyClass === undefined
            ? 'text-brutal-muted-foreground'
            : toValue(options.emptyClass)

        return cn(
            baseClass,
            !state.hasValue && emptyClass,
            toValue(options.class)
        )
    })

    return {
        hasValue,
        triggerClasses,
    }
}

import { computed, toValue, type ComputedRef, type MaybeRefOrGetter } from 'vue'

export interface UseSelectionDisplayTextOptions<TItem> {
    selectedItems: MaybeRefOrGetter<readonly TItem[]>
    placeholder: MaybeRefOrGetter<string>
    multiple?: MaybeRefOrGetter<boolean | undefined>
    maxDisplay?: MaybeRefOrGetter<number | undefined>
    getLabel?: (item: TItem) => string
    formatCount?: (count: number) => string
    formatList?: (labels: string[]) => string
}

function defaultGetLabel<TItem>(item: TItem): string {
    if (typeof item === 'string') return item
    if (typeof item === 'number' || typeof item === 'boolean') return String(item)
    if (item && typeof item === 'object' && 'label' in item) {
        const label = (item as { label?: unknown }).label
        if (typeof label === 'string') return label
    }
    return ''
}

function defaultFormatList(labels: string[]): string {
    if (typeof Intl !== 'undefined' && 'ListFormat' in Intl) {
        const listFormatter = new Intl.ListFormat(undefined, { style: 'long', type: 'conjunction' })
        return listFormatter.format(labels)
    }
    return labels.join(', ')
}

export function useSelectionDisplayText<TItem>(
    options: UseSelectionDisplayTextOptions<TItem>
): ComputedRef<string> {
    return computed(() => {
        const items = [...toValue(options.selectedItems)]
        const placeholder = toValue(options.placeholder)
        const getLabel = options.getLabel ?? defaultGetLabel

        if (!toValue(options.multiple)) {
            const selected = items[0]
            return selected ? getLabel(selected) : placeholder
        }

        if (items.length === 0) return placeholder

        const maxDisplay = toValue(options.maxDisplay) ?? 3
        if (items.length <= maxDisplay) {
            const formatList = options.formatList ?? defaultFormatList
            return formatList(items.map(getLabel))
        }

        return options.formatCount?.(items.length) ?? `${items.length} selected`
    })
}

